440	export function renderReply(
441	  session: ChatSession,
442	  done: boolean,
443	  parsers: ScheduleParsers,
444	  replyHeader?: string,
445	): RenderResult {
446	  // Header（如 ASK 的「我選擇了：X」）是恆定前綴，streaming 每幀都要帶，
447	  // 否則只有 final render 有、使用者整輪看不到自己選了什麼。
448	  const header = replyHeader ? replyHeader + "\n\n" : "";
449	  const toolLines = toolPrefixLines(session);
450	  const tools = toolLines.length ? toolLines.join("\n") + "\n\n" : "";
451	  const cursor = done ? "" : " ▍";
452	  const emptyFallback = () => {
453	    if (!done) return session.thinkingBuffer ? "" : "Thinking…";
454	    const n = session.toolTimeline.length;
455	    return n > 0 ? `(no text yet — ${n} tool call${n === 1 ? "" : "s"} so far)` : "(no response)";
456	  };
457	
458	  // Show thinking progress during streaming (hide when done)
459	  let thinkingBlock = "";
460	  if (!done && session.thinkingBuffer) {
461	    // Show last ~200 chars of thinking as blockquote
462	    const t = session.thinkingBuffer;
463	    const preview = t.length > 200 ? "…" + t.slice(-200) : t;
464	    thinkingBlock = "💭 " + preview.split("\n").join("\n> ") + "\n\n";
465	  }
466	
467	  const raw = session.buffer || emptyFallback();
468	  const stripped = transformReplyTokens(raw, parsers).text;
469	  let body = stripped || emptyFallback();
470	  // 扣除 header/tools/thinkingBlock/cursor 佔用的長度，避免拼接後超過 Telegram 4096 上限
471	  const overhead = header.length + tools.length + thinkingBlock.length + cursor.length;
472	  const bodyBudget = Math.max(TG_MAX - overhead, 200);
473	  if (body.length > bodyBudget) {
474	    body = "…" + body.slice(-bodyBudget);
475	  }
476	
477	  const plain = header + tools + thinkingBlock + body + cursor;
478	  const { html } = markdownToHtml(plain);
479	  // HTML 膨脹超過 Telegram 4096 上限時 fallback 到純文字（markdown budget 已 ≤3900，純文字必定安全）
480	  if (html.length > 4096) {
481	    return { content: plain, parseMode: undefined };
482	  }
483	  return { content: html, parseMode: "HTML" };
484	}
